  1	import * as React from 'react';
  2	import { useTranslation } from 'react-i18next';
  3	import { Tooltip } from '@patternfly/react-core';
  4	import {
  5	  DEFAULT_LAYER,
  6	  DEFAULT_WHEN_OFFSET,
  7	  Layer,
  8	  Node,
  9	  ScaleDetailsLevel,
 10	  TaskNode,
 11	  TOP_LAYER,
 12	  useDetailsLevel,
 13	  useHover,
 14	  WhenDecorator,
 15	  WithContextMenuProps,
 16	  WithSelectionProps,
 17	} from '@patternfly/react-topology';
 18	import classNames from 'classnames';
 19	import { observer } from 'mobx-react';
 20	import { Link } from 'react-router-dom-v5-compat';
 21	import { NodeType } from './const';
 22	import { PipelineRunModel, TaskModel } from '../../models';
 23	import { getReferenceForModel } from '../pipelines-overview/utils';
 24	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 25	import { ComputedStatus, TaskKind } from '../../types';
 26	import { pipelineRunFilterReducer } from '../utils/pipeline-filter-reducer';
 27	import {
 28	  createStepStatus,
 29	  StepStatus,
 30	} from '../pipelines-details/pipeline-step-utils';
 31	import { PipelineVisualizationStepList } from '../pipelines-details/PipelineVisualizationStepList';
 32	import { resourcePathFromModel } from '../utils/utils';
 33	import { getTooltipContent } from './utils';
 34	import './PipelineTaskNode.scss';
 35	
 36	type PipelineTaskNodeProps = {
 37	  element: Node;
 38	} & WithContextMenuProps &
 39	  WithSelectionProps;
 40	
 41	const PipelineTaskNode: React.FunctionComponent<PipelineTaskNodeProps> = ({
 42	  element,
 43	  onContextMenu,
 44	  contextMenuOpen,
 45	  ...rest
 46	}) => {
 47	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 48	  const data = element.getData();
 49	  const [hover, hoverRef] = useHover();
 50	  const taskRef = React.useRef();
 51	  const detailsLevel = useDetailsLevel();
 52	  const isFinallyTask = element.getType() === NodeType.FINALLY_NODE;
 53	  let resources;
 54	  if (data.task?.taskRef?.resolver === 'cluster') {
 55	    const taskName = data.task.taskRef?.params?.find(
 56	      (param) => param.name === 'name',
 57	    )?.value;
 58	    const taskNamespace = data.task.taskRef?.params?.find(
 59	      (param) => param.name === 'namespace',
 60	    )?.value;
 61	
 62	    resources = {
 63	      kind: getReferenceForModel(TaskModel),
 64	      name: taskName,
 65	      namespace: taskNamespace || data.pipeline.metadata.namespace,
 66	      prop: 'task',
 67	    };
 68	  } else if (data.task?.taskRef) {
 69	    resources = {
 70	      kind: getReferenceForModel(TaskModel),
 71	      name: data.task.taskRef.name,
 72	      namespace: data.pipeline.metadata.namespace,
 73	      prop: 'task',
 74	    };
 75	  }
 76	  const [task] = useK8sWatchResource<TaskKind>(resources);
 77	
 78	  const computedTask = task && Object.keys(task).length ? task : data.task;
 79	  const stepList =
 80	    computedTask?.status?.steps ||
 81	    computedTask?.spec?.steps ||
 82	    computedTask?.taskSpec?.steps ||
 83	    [];
 84	
 85	  const pipelineRunStatus =
 86	    data.pipelineRun && pipelineRunFilterReducer(data.pipelineRun);
 87	  const isSkipped = !!(
 88	    computedTask &&
 89	    data.pipelineRun?.status?.skippedTasks?.some(
 90	      (t) => t.name === data.task.name,
 91	      (t) => t.name === computedTask.name,
 92	    )
 93	  );
 94	
 95	  const taskStatus = data.task?.status || {
 96	    duration: '',
 97	    reason: ComputedStatus.Idle,
 98	  };
 99	  if (
100	    pipelineRunStatus === ComputedStatus.Failed ||
101	    pipelineRunStatus === ComputedStatus.Cancelled
102	  ) {
103	    if (
104	      data.task?.status?.reason === ComputedStatus.Idle ||
105	      data.task?.status?.reason === ComputedStatus.Pending
106	    ) {
107	      taskStatus.reason = ComputedStatus.Cancelled;
108	    }
109	  }
110	  if (isSkipped) {
111	    taskStatus.reason = ComputedStatus.Skipped;
112	  }
113	
114	  const stepStatusList: StepStatus[] = stepList.map((step) =>
115	    createStepStatus(step, taskStatus),
116	  );
117	  const { pipelineRun } = data;
118	  const succeededStepsCount = stepStatusList.filter(
119	    ({ status }) => status === ComputedStatus.Succeeded,
120	  ).length;
121	
122	  const badge =
123	    stepStatusList.length > 0 && data.status
124	      ? `${succeededStepsCount}/${stepStatusList.length}`
125	      : null;
126	
127	  const passedData = React.useMemo(() => {
128	    const newData = { ...data };
129	    Object.keys(newData).forEach((key) => {
130	      if (newData[key] === undefined) {
131	        delete newData[key];
132	      }
133	    });
134	    return newData;
135	  }, [data]);
136	
137	  const hasTaskIcon = !!(data.taskIconClass || data.taskIcon);
138	  const tooltipContent = getTooltipContent(data.task?.status?.reason, t);
139	  const whenDecorator = data.whenStatus ? (
140	    <WhenDecorator
141	      element={element}
142	      status={data.whenStatus}
143	      leftOffset={
144	        hasTaskIcon
145	          ? DEFAULT_WHEN_OFFSET + (element.getBounds().height - 4) * 0.75
146	          : DEFAULT_WHEN_OFFSET
147	      }
148	      toolTip={tooltipContent}
149	    />
150	  ) : null;
151	
152	  // eslint-disable-next-line no-unsafe-optional-chaining
153	  const { name: plrName, namespace } = pipelineRun?.metadata;
154	  const path = plrName
155	    ? `${resourcePathFromModel(
156	        PipelineRunModel,
157	        plrName,
158	        namespace,
159	      )}/logs?taskName=${element.getLabel()}`
160	    : undefined;
161	
162	  const enableLogLink =
163	    data.status !== ComputedStatus.Idle &&
164	    data.status !== ComputedStatus.Pending &&
165	    data.status !== ComputedStatus.Cancelled &&
166	    data.status !== ComputedStatus.Skipped &&
167	    !!path;
168	
169	  const taskNode = (
170	    <TaskNode
171	      className="odc-pipeline-topology__task-node"
172	      element={element}
173	      onContextMenu={data.showContextMenu ? onContextMenu : undefined}
174	      contextMenuOpen={contextMenuOpen}
175	      scaleNode={
176	        (hover || contextMenuOpen) && detailsLevel !== ScaleDetailsLevel.high
177	      }
178	      hideDetailsAtMedium
179	      {...passedData}
180	      {...rest}
181	      badge={badge}
182	      truncateLength={element.getData()?.label?.length}
183	    >
184	      {whenDecorator}
185	    </TaskNode>
186	  );
187	
188	  const classes = classNames('odc-pipeline-topology__task-node', {
189	    'is-link': enableLogLink,
190	  });
191	  return (
192	    <Layer
193	      id={
194	        detailsLevel !== ScaleDetailsLevel.high && (hover || contextMenuOpen)
195	          ? TOP_LAYER
196	          : DEFAULT_LAYER
197	      }
198	    >
199	      <g
200	        data-test={`task ${element.getLabel()}`}
201	        className={classes}
202	        ref={hoverRef}
203	      >
204	        <Tooltip
205	          enableFlip={true}
206	          triggerRef={taskRef}
207	          content={
208	            <PipelineVisualizationStepList
209	              isSpecOverview={!data.status}
210	              taskName={element.getLabel()}
211	              steps={stepStatusList}
212	              isFinallyTask={isFinallyTask}
213	            />
214	          }
215	        >
216	          <g ref={taskRef}>
217	            {enableLogLink ? <Link to={path}>{taskNode}</Link> : taskNode}
218	          </g>
219	        </Tooltip>
220	      </g>
221	    </Layer>
222	  );
223	};
224	
225	export default React.memo(observer(PipelineTaskNode));

